// Montar dados para o GPT gerar relatório
const stats = $('Estatísticas Gerais').first().json;
const leadsAtivos = $('Leads Ativos Semana').all().map(i => i.json);
const reunioes = $('Estatísticas Reuniões').first().json;

let leadsDetalhe = '';
if (leadsAtivos && leadsAtivos.length > 0 && leadsAtivos[0].nome) {
  leadsDetalhe = leadsAtivos.map(l => {
    return `- ${l.nome} (${l.whatsapp}) | Cat: ${l.categoria || 'N/A'} | Interesses: ${l.interesses || 'N/A'} | Msgs: ${l.total_mensagens} | Resumo: ${l.historico_resumo || 'Sem resumo'}`;
  }).join('\n');
} else {
  leadsDetalhe = 'Nenhum lead ativo esta semana.';
}

return [{
  json: {
    promptRelatorio: `Gere um relatório semanal profissional e detalhado da Buildesign para o dono da agência.

DADOS DA SEMANA:

📊 VISÃO GERAL:
- Total de leads no banco: ${stats.total_leads || 0}
- Novos leads esta semana: ${stats.novos_semana || 0}
- Leads ativos esta semana: ${stats.ativos_semana || 0}

🌡️ CLASSIFICAÇÃO:
- Muito Quentes: ${stats.muito_quentes || 0}
- Quentes: ${stats.quentes || 0}
- Mornos: ${stats.mornos || 0}
- Frios: ${stats.frios || 0}

📈 STATUS:
- Convertidos: ${stats.convertidos || 0}
- Com reunião agendada: ${stats.com_reuniao || 0}
- Em follow-up: ${stats.em_followup || 0}
- Perdidos: ${stats.perdidos || 0}

📅 REUNIÕES:
- Total semana: ${reunioes.total_reunioes_semana || 0}
- Realizadas: ${reunioes.realizadas || 0}
- Pendentes: ${reunioes.pendentes || 0}
- Canceladas: ${reunioes.canceladas || 0}

👥 LEADS ATIVOS DETALHADOS:
${leadsDetalhe}

IMPORTANTE: Formate como mensagem de WhatsApp (use emojis, quebras de linha, seja visual). Inclua:
1. Resumo executivo (2-3 linhas)
2. Números da semana
3. Destaque dos leads mais quentes (com recomendação de ação)
4. Análise de tendência
5. Sugestões de ação para a próxima semana

Responda APENAS com o texto do relatório, pronto para enviar no WhatsApp.`
  }
}];

const response = $input.first().json;
const relatorio = response.choices[0].message.content;

return [{ json: { relatorio } }];
